// ============================================================================
// Helper: Determine default branch from fetched refs
// ============================================================================

// Find the default branch after fetch by checking:
// 1. refs/remotes/origin/HEAD (symbolic ref from server)
// 2. refs/remotes/origin/main
// 3. refs/remotes/origin/master
static bool determine_default_branch(GitRepository* repo, const char* remote_name,
                                     char* out_branch, size_t max_len) {
    if (!repo || !remote_name || !out_branch || max_len == 0) return false;
    
    wchar_t git_dir_wide[Git::MAX_PATH_LEN];
    utf8_to_wide_n(repo->git_dir, git_dir_wide, Git::MAX_PATH_LEN);
    
    // 1. Try to read refs/remotes/origin/HEAD (symbolic ref)
    wchar_t head_path[Git::MAX_PATH_LEN];
    swprintf_s(head_path, L"%s\\refs\\remotes\\%hs\\HEAD", git_dir_wide, remote_name);
    
    char content[256];
    size_t len = read_file(head_path, content, sizeof(content) - 1);
    if (len > 0) {
        content[len] = '\0';
        // Parse "ref: refs/remotes/origin/main" format
        if (strncmp(content, "ref: ", 5) == 0) {
            const char* ref_path = content + 5;
            // Strip trailing newline
            char* nl = strchr((char*)ref_path, '\n');
            if (nl) *nl = '\0';
            
            // Extract branch name: refs/remotes/origin/main -> main
            char prefix[128];
            snprintf(prefix, sizeof(prefix), "refs/remotes/%s/", remote_name);
            size_t prefix_len = strlen(prefix);
            
            if (strncmp(ref_path, prefix, prefix_len) == 0) {
                strncpy_s(out_branch, max_len, ref_path + prefix_len, _TRUNCATE);
                return true;
            }
        }
    }
    
    // 2. Check if refs/remotes/origin/main exists
    wchar_t main_path[Git::MAX_PATH_LEN];
    swprintf_s(main_path, L"%s\\refs\\remotes\\%hs\\main", git_dir_wide, remote_name);
    
    len = read_file(main_path, content, sizeof(content) - 1);
    if (len >= Git::SHA1_HEX_SIZE) {
        strncpy_s(out_branch, max_len, "main", _TRUNCATE);
        return true;
    }
    
    // 3. Check if refs/remotes/origin/master exists
    wchar_t master_path[Git::MAX_PATH_LEN];
    swprintf_s(master_path, L"%s\\refs\\remotes\\%hs\\master", git_dir_wide, remote_name);
    
    len = read_file(master_path, content, sizeof(content) - 1);
    if (len >= Git::SHA1_HEX_SIZE) {
        strncpy_s(out_branch, max_len, "master", _TRUNCATE);
        return true;
    }
    
    return false;
}

// ============================================================================
// Helper: Create local branch from remote tracking branch
// ============================================================================

static bool create_local_branch_from_remote(GitRepository* repo, const char* remote_name,
                                            const char* branch_name) {
    if (!repo || !remote_name || !branch_name) return false;
    
    wchar_t git_dir_wide[Git::MAX_PATH_LEN];
    utf8_to_wide_n(repo->git_dir, git_dir_wide, Git::MAX_PATH_LEN);
    
    // Read SHA from remote tracking ref
    wchar_t remote_ref_path[Git::MAX_PATH_LEN];
    swprintf_s(remote_ref_path, L"%s\\refs\\remotes\\%hs\\%hs",
               git_dir_wide, remote_name, branch_name);
    
    // Convert forward slashes in branch name (e.g., feature/foo)
    for (wchar_t* p = remote_ref_path; *p; p++) {
        if (*p == L'/') *p = L'\\';
    }
    
    char sha_content[64];
    size_t len = read_file(remote_ref_path, sha_content, sizeof(sha_content) - 1);
    if (len < Git::SHA1_HEX_SIZE) {
        LOG("create_local_branch_from_remote: failed to read remote ref for '%s'", branch_name);
        return false;
    }
    sha_content[Git::SHA1_HEX_SIZE] = '\0';
    
    // Create local branch ref
    char local_ref_path[Git::MAX_REF_NAME + 16];
    snprintf(local_ref_path, sizeof(local_ref_path), "refs/heads/%s", branch_name);
    
    if (!git_ref_update(repo, local_ref_path, sha_content)) {
        LOG("create_local_branch_from_remote: failed to create local ref '%s'", local_ref_path);
        return false;
    }
    
    // Update HEAD to point to new branch
    wchar_t head_path[Git::MAX_PATH_LEN];
    swprintf_s(head_path, L"%s\\HEAD", git_dir_wide);
    
    char head_content[128];
    snprintf(head_content, sizeof(head_content), "ref: refs/heads/%s\n", branch_name);
    
    if (!write_file_atomic(head_path, head_content, strlen(head_content))) {
        LOG("create_local_branch_from_remote: failed to update HEAD");
        return false;
    }
    
    // Update repo state
    strcpy_s(repo->head_ref, branch_name);
    strcpy_s(repo->head_sha, sha_content);
    repo->head_detached = false;
    
    return true;
}

// ============================================================================
// Main Clone Function
// ============================================================================

bool git_clone(const CloneOptions* options, CloneProgress* progress, CloneResult* result) {
    if (!options || !result) {
        return false;
    }
    
    memset(result, 0, sizeof(CloneResult));
    int64_t start_time = GetTickCount64();
    
    auto update_progress = [&](ClonePhase phase) {
        if (progress) {
            progress->phase.store(phase);
            if (options->progress_callback) {
                options->progress_callback(progress, options->progress_user_data);
            }
        }
    };
    
    // Validate URL
    if (!git_clone_validate_url(options->url)) {
        strncpy_s(result->error_message, sizeof(result->error_message),
                  "Invalid repository URL. Only HTTPS URLs are supported.", _TRUNCATE);
        update_progress(ClonePhase::Failed);
        return false;
    }
    
    // Check if we're in resume mode (for testing - skips download)
    const char* resume_env = getenv("GITSMARTER_RESUME_PACK");
    bool resume_mode = (resume_env && strcmp(resume_env, "1") == 0);

    // Validate destination doesn't already exist (unless in resume mode)
    DWORD attrs = GetFileAttributesW(options->destination);
    if (attrs != INVALID_FILE_ATTRIBUTES && !resume_mode) {
        strncpy_s(result->error_message, sizeof(result->error_message),
                  "Destination directory already exists.", _TRUNCATE);
        update_progress(ClonePhase::Failed);
        return false;
    }

    // Check cancellation
    if (progress && progress->base.cancel_requested.load()) {
        update_progress(ClonePhase::Cancelled);
        return false;
    }

    // Phase 1: Initialize repository (skip if resuming and .git exists)
    update_progress(ClonePhase::Initializing);
    int64_t phase_start = GetTickCount64();

    bool skip_init = false;
    if (resume_mode && attrs != INVALID_FILE_ATTRIBUTES) {
        // Check if .git already exists
        wchar_t git_dir[Git::MAX_PATH_LEN];
        swprintf_s(git_dir, L"%s\\.git", options->destination);
        if (GetFileAttributesW(git_dir) != INVALID_FILE_ATTRIBUTES) {
            LOG("git_clone: resume mode - skipping init, .git exists");
            skip_init = true;
        }
    }

    if (!skip_init && !git_repo_init(options->destination)) {
        strncpy_s(result->error_message, sizeof(result->error_message),
                  "Failed to initialize repository.", _TRUNCATE);
        update_progress(ClonePhase::Failed);
        return false;
    }
    TELEM_CLONE_PHASE(Initializing, (uint32_t)(GetTickCount64() - phase_start), 0, 0);

    // Roll back the destination only when we are the ones who created it.
    auto cleanup_dest = [&]() {
        if (!skip_init) {
            delete_directory_recursive(options->destination);
        }
    };

    // Open the newly created repo
    GitRepository repo = {};
    if (!git_repo_open(&repo, options->destination)) {
        strncpy_s(result->error_message, sizeof(result->error_message),
                  "Failed to open initialized repository.", _TRUNCATE);
        cleanup_dest();
        update_progress(ClonePhase::Failed);
        return false;
    }

    // Check cancellation
    if (progress && progress->base.cancel_requested.load()) {
        git_repo_close(&repo);
        cleanup_dest();
        update_progress(ClonePhase::Cancelled);
        return false;
    }

    // Phase 2: Add remote
    update_progress(ClonePhase::AddingRemote);
    phase_start = GetTickCount64();

    if (!git_remote_add(&repo, "origin", options->url)) {
        strncpy_s(result->error_message, sizeof(result->error_message),
                  "Failed to add remote.", _TRUNCATE);
        git_repo_close(&repo);
        cleanup_dest();
        update_progress(ClonePhase::Failed);
        return false;
    }
    TELEM_CLONE_PHASE(AddingRemote, (uint32_t)(GetTickCount64() - phase_start), 0, 0);

    // Reload repo to pick up new remote config
    git_repo_close(&repo);
    if (!git_repo_open(&repo, options->destination)) {
        strncpy_s(result->error_message, sizeof(result->error_message),
                  "Failed to reload repository after adding remote.", _TRUNCATE);
        cleanup_dest();
        update_progress(ClonePhase::Failed);
        return false;
    }

    // Check cancellation
    if (progress && progress->base.cancel_requested.load()) {
        git_repo_close(&repo);
        cleanup_dest();
        update_progress(ClonePhase::Cancelled);
        return false;
    }
    
    // Phase 3: Fetch from remote
    update_progress(ClonePhase::Fetching);
    phase_start = GetTickCount64();
    
    FetchOptions fetch_opts = {};
    fetch_opts.mode = FetchMode::Full;  // Get all refs for a clone
    
    // Forward fetch progress if we have progress tracking
    if (progress) {
        fetch_opts.progress_callback = [](const FetchProgress* fp, void* ud) {
            CloneProgress* cp = static_cast<CloneProgress*>(ud);
            if (!cp) return;
            FetchPhase old_phase = cp->fetch_phase.load();
            FetchPhase new_phase = fp->phase.load();

            // Record phase transition timestamps
            uint64_t now = GetTickCount64();
            if (new_phase != old_phase) {
                if (new_phase == FetchPhase::Receiving && old_phase != FetchPhase::Receiving) {
                    // Download/parse starting
                    cp->download_start_ms.store(now, std::memory_order_relaxed);
                    cp->parse_start_ms.store(now, std::memory_order_relaxed);
                }
                else if (new_phase == FetchPhase::ResolvingDeltas) {
                    // Download/parse ended, delta resolution starting
                    cp->download_end_ms.store(now, std::memory_order_relaxed);
                    cp->parse_end_ms.store(now, std::memory_order_relaxed);
                    cp->delta_start_ms.store(now, std::memory_order_relaxed);
                }
                else if (new_phase == FetchPhase::Updating && old_phase == FetchPhase::ResolvingDeltas) {
                    // Delta resolution ended
                    cp->delta_end_ms.store(now, std::memory_order_relaxed);
                }
            }

            cp->fetch_phase.store(new_phase);
            cp->objects_done.store(fp->objects_done.load());
            cp->objects_total.store(fp->objects_total.load());
            cp->bytes_received.store(fp->bytes_received.load());

            // Also forward delta progress if available
            cp->deltas_done.store(fp->deltas_done.load());
            cp->deltas_total.store(fp->deltas_total.load());
            cp->bytes_total.store(fp->bytes_total.load());
        };
        fetch_opts.progress_user_data = progress;
    }
    
    FetchResult fetch_result = {};
    if (!git_fetch(&repo, "origin", &fetch_opts, &fetch_result)) {
        snprintf(result->error_message, sizeof(result->error_message),
                 "Fetch failed: %s", fetch_result.error_message);
        git_repo_close(&repo);
        cleanup_dest();
        update_progress(ClonePhase::Failed);
        return false;
    }
    TELEM_CLONE_PHASE(Fetching, (uint32_t)(GetTickCount64() - phase_start), fetch_result.objects_received, fetch_result.bytes_received);

    result->objects_received = fetch_result.objects_received;
    result->bytes_received = fetch_result.bytes_received;

    // Reload pack files - the fetch just wrote objects that the repo doesn't know about
    git_unload_packs(&repo);
    git_load_packs(&repo);

    // Check cancellation
    if (progress && progress->base.cancel_requested.load()) {
        git_repo_close(&repo);
        cleanup_dest();
        update_progress(ClonePhase::Cancelled);
        return false;
    }
    
    // Phase 4: Determine default branch
    update_progress(ClonePhase::DeterminingBranch);
    phase_start = GetTickCount64();
    
    char default_branch[Git::MAX_REF_NAME] = {0};
    if (!determine_default_branch(&repo, "origin", default_branch, sizeof(default_branch))) {
        // Fallback: try common branch names
        strncpy_s(default_branch, sizeof(default_branch), "main", _TRUNCATE);
    }
    
    strcpy_s(result->default_branch, default_branch);
    TELEM_CLONE_PHASE(DeterminingBranch, (uint32_t)(GetTickCount64() - phase_start), 0, 0);
    
    // Create local branch from remote tracking branch
    if (!create_local_branch_from_remote(&repo, "origin", default_branch)) {
        snprintf(result->error_message, sizeof(result->error_message),
                 "Failed to create local branch '%s'", default_branch);
        git_repo_close(&repo);
        cleanup_dest();
        update_progress(ClonePhase::Failed);
        return false;
    }

    // Check cancellation
    if (progress && progress->base.cancel_requested.load()) {
        git_repo_close(&repo);
        cleanup_dest();
        update_progress(ClonePhase::Cancelled);
        return false;
    }
    
    // Phase 5: Checkout working tree (if requested)
    if (options->checkout) {
        phase_start = GetTickCount64();
        update_progress(ClonePhase::CheckingOut);

        // Record checkout start timestamp
        if (progress) {
            progress->checkout_start_ms.store(phase_start, std::memory_order_relaxed);
        }
        
        // Read the commit to get tree SHA
        GitCommit commit = {};
        if (!git_read_commit(&repo, repo.head_sha, &commit)) {
            strncpy_s(result->error_message, sizeof(result->error_message),
                      "Failed to read HEAD commit.", _TRUNCATE);
            git_repo_close(&repo);
            cleanup_dest();
            update_progress(ClonePhase::Failed);
            return false;
        }

        // Clone-optimized checkout with concurrent index building
        // Eliminates separate tree traversal and per-file stat syscalls
        GitIndexFull clone_index = {};
        if (!git_checkout_tree_for_clone(&repo, commit.tree_sha, progress, &clone_index)) {
            strncpy_s(result->error_message, sizeof(result->error_message),
                      "Failed to checkout working tree.", _TRUNCATE);
            git_index_close_full(&clone_index);
            git_repo_close(&repo);
            cleanup_dest();
            update_progress(ClonePhase::Failed);
            return false;
        }

        // Write index file
        if (!git_index_lock(&repo, 5000)) {
            strncpy_s(result->error_message, sizeof(result->error_message),
                      "Failed to lock index.", _TRUNCATE);
            git_index_close_full(&clone_index);
            git_repo_close(&repo);
            cleanup_dest();
            update_progress(ClonePhase::Failed);
            return false;
        }

        if (!git_index_write(&repo, &clone_index)) {
            strncpy_s(result->error_message, sizeof(result->error_message),
                      "Failed to write index.", _TRUNCATE);
            git_index_unlock(&repo);
            git_index_close_full(&clone_index);
            git_repo_close(&repo);
            cleanup_dest();
            update_progress(ClonePhase::Failed);
            return false;
        }

        git_index_unlock(&repo);

        // Use files_done (actual files written) not entry_count (includes submodules)
        result->files_checked_out = progress ? progress->files_done.load() : clone_index.entry_count;
        git_index_close_full(&clone_index);

        // Record checkout end timestamp
        if (progress) {
            progress->checkout_end_ms.store(GetTickCount64(), std::memory_order_relaxed);
        }

        TELEM_CLONE_PHASE(CheckingOut, (uint32_t)(GetTickCount64() - phase_start), result->files_checked_out, 0);
    }
    
    // Success!
    git_repo_close(&repo);

    result->success = true;
    result->duration_ms = GetTickCount64() - start_time;

    // Capture final memory stats
    result->peak_memory_bytes = get_peak_process_memory_bytes();
    size_t current_memory = get_process_memory_bytes();

    LOG_INFO("clone_memory_summary: current=%.1fMB peak=%.1fMB",
        current_memory / (1024.0 * 1024.0),
        result->peak_memory_bytes / (1024.0 * 1024.0));
    TELEM_CLONE_PHASE(Complete, (uint32_t)result->duration_ms, result->objects_received, result->bytes_received);

    update_progress(ClonePhase::Complete);
    return true;
}
